def is_leap(year):
    if year % 400 == 0:
        return True
    if year % 100 == 0:
        return False
    return year % 4 == 0


def days_before_date(date_str):
    d, m, y = map(int, date_str.split('-'))
    month_days = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]

    total = 0

    for year in range(1, y):
        total += 366 if is_leap(year) else 365

    for month in range(1, m):
        if month == 2 and is_leap(y):
            total += 29
        else:
            total += month_days[month - 1]

    total += d
    return total


def days_between(date1, date2):
    return abs(days_before_date(date1) - days_before_date(date2))

print(days_between("27-03-2026", "01-04-2026"))
print(days_between("28-02-2024", "01-03-2024"))
